scwin.gr_out_onafteredit = async function (row, columnIndex, value) {
  var colid = gr_out.getColumnID(columnIndex);
  if (colid == "oilStatCd") {
    if (ds_out.getCellData(row, "oilingMm") != "") {
      // scwin.f_RetrieveOilStatAvgUpr(ds_out.getCellData(row, "oilingMm"), ds_out.getCellData(row, "oilStatCd"), 2);
      ds_condition2.set("stDt", ds_out.getCellData(row, "oilingMm"));
      ds_condition2.set("oilStatCd", ds_out.getCellData(row, "oilStatCd"));
      ds_condition2.set("sortGub", 2);
      var rs = await $c.sbm.execute($p, sbm_oilStatAvgUpr);
      if (rs.responseJSON.resultDataSet[0].Msg == "SUCC") {
        if (ds_oilStatAvgUpr.getRowCount() > 0) {
          ds_out.setCellData(row, "oilingUpr", ds_oilStatAvgUpr.getCellData(0, "oilingUpr"));
        }
      }
      ;
    }
  }

  // if (colid == "dtc1"){
  //     ds_out.setCellData(row, "sumDtc", parseFloat(ds_out.getCellData(row, "dtc1")) + parseFloat(ds_out.getCellData(row, "dtc2")));
  // }else if (colid == "dtc2"){
  //     ds_out.setCellData(row, "sumDtc", parseFloat(ds_out.getCellData(row, "dtc1")) + parseFloat(ds_out.getCellData(row, "dtc2")));
  // }
  if (colid == "dtc1" || colid == "dtc2") {
    //dtc1(신선), dtc2(공산)
    if ($c.util.isEmpty($p, ds_out.getCellData(row, "dtc1"))) {
      ds_out.setCellData(row, "dtc1", 0);
    } else if ($c.util.isEmpty($p, ds_out.getCellData(row, "dtc2"))) {
      ds_out.setCellData(row, "dtc2", 0);
    }
    ds_out.setCellData(row, "sumDtc", parseFloat(ds_out.getCellData(row, "dtc1")) + parseFloat(ds_out.getCellData(row, "dtc2")));
    if (ds_out.getCellData(row, "sumDtc") > 0) {
      if (ds_out.getCellData(row, "fleffcncy") != "" && ds_out.getCellData(row, "fleffcncy") != 0) {
        // 운행거리합계/연비
        var stdOilingVol = parseFloat(ds_out.getCellData(row, "sumDtc")) / parseFloat(ds_out.getCellData(row, "fleffcncy"));
        ds_out.setCellData(row, "stdOilingVol", Math.round(stdOilingVol));
      }
      scwin.f_Prflos(row);
    }
  }
  if (colid == "oilingMm") {
    //주유월
    if (ds_out.getCellData(row, "oilStatCd") != "") {
      // scwin.f_RetrieveOilStatAvgUpr(ds_out.getCellData(row, "oilingMm"),ds_out.getCellData(row, "oilStatCd"), 2);
      ds_condition2.set("stDt", ds_out.getCellData(row, "oilingMm"));
      ds_condition2.set("oilStatCd", ds_out.getCellData(row, "oilStatCd"));
      ds_condition2.set("sortGub", 2);
      var rs = await $c.sbm.execute($p, sbm_oilStatAvgUpr);
      if (rs.responseJSON.resultDataSet[0].Msg == "SUCC") {
        if (ds_oilStatAvgUpr.getRowCount() > 0) {
          ds_out.setCellData(row, "oilingUpr", ds_oilStatAvgUpr.getCellData(0, "oilingUpr"));
        }
      }
      ;
    }
    scwin.f_Prflos(row);
  } else if (colid == "fleffcncy") {
    //차량정보_기준연비
    if ($c.util.isEmpty($p, ds_out.getCellData(row, "fleffcncy"))) {
      ds_out.setCellData(row, "fleffcncy", 0);
    }
    if (ds_out.getCellData(row, "sumDtc") != "" && ds_out.getCellData(row, "sumDtc") != 0) {
      // 운행거리합계/연비
      var stdOilingVol = parseFloat(ds_out.getCellData(row, "sumDtc")) / parseFloat(ds_out.getCellData(row, "fleffcncy"));
      ds_out.setCellData(row, "stdOilingVol", Math.round(stdOilingVol));
    }
    scwin.f_Prflos(row);
  } else if (colid == "sumDtc") {
    //운행거리_합계
    if (ds_out.getCellData(row, "fleffcncy") != "" && ds_out.getCellData(row, "fleffcncy") != 0) {
      // 운행거리합계/연비
      var stdOilingVol = parseFloat(ds_out.getCellData(row, "sumDtc")) / parseFloat(ds_out.getCellData(row, "fleffcncy"));
      ds_out.setCellData(row, "stdOilingVol", Math.round(stdOilingVol));
    }
    scwin.f_Prflos(row);
  } else if (colid == "stdOilingVol") {
    //연비기준현황_주유량
    if (ds_out.getCellData(row, "oilingUpr") != "" && ds_out.getCellData(row, "oilingUpr") != 0) {
      var stdOilingVol = parseFloat(ds_out.getCellData(row, "stdOilingVol")); //주유량
      var oilingUpr = parseFloat(ds_out.getCellData(row, "oilingUpr")); //단가

      //주유공급가
      ds_out.setCellData(row, "stdAmt", stdOilingVol * oilingUpr);
      //주유세액
      ds_out.setCellData(row, "stdVatAmt", Math.round(stdOilingVol * oilingUpr * 0.1));
      //합계
      ds_out.setCellData(row, "stdAmtTot", Math.round(stdOilingVol * oilingUpr * 1.1));
    }
    scwin.f_Prflos(row);
  } else if (colid == "realAmt") {
    //실주유현황_공급가
    if ($c.util.isEmpty($p, ds_out.getCellData(row, "realAmt"))) {
      ds_out.setCellData(row, "realAmt", 0);
    }
    var realAmt = ds_out.getCellData(row, "realAmt");
    ds_out.setCellData(row, "realVatAmt", Math.round(realAmt * 0.1));
    ds_out.setCellData(row, "realAmtTot", Math.round(realAmt * 1.1));
    scwin.f_Prflos(row);
  } else if (colid == "deductAmt") {
    if ($c.util.isEmpty($p, ds_out.getCellData(row, "deductAmt"))) {
      ds_out.setCellData(row, "deductAmt", 0);
    }
    scwin.f_Prflos2(row);
  }
};
